def request_chain(json: dict, timeout=60):
    langchain_headers = {
        "Host": "aime-langchain-engine-server",
        "X-Arsenal-Auth": "aime-reinforcement-learning-environment-access",
        "Content-Type": "application/json",
    }

    last_exception = None
    for langchain_server_url in dict.fromkeys(LANGCHAIN_SERVER_URLS):
        try:
            return requests.post(langchain_server_url, headers=langchain_headers, json=json, timeout=timeout)
        except requests.exceptions.RequestException as exc:
            last_exception = exc
            print(f"Request to {langchain_server_url} failed: {exc}")
    raise last_exception
    

