class WencaiClient:
    def __init__(self, model="aime-multimodal-ucwlai"):
        self.model = model


    def encode_image(self, image_path):
        pil_image = Image.open(image_path)
        img_byte_arr = BytesIO()
        pil_image.save(img_byte_arr, format=pil_image.format)
        return base64.b64encode(img_byte_arr.getvalue()).decode('utf-8')

    def update_message(self, messages):
        for i, item in enumerate(messages):
            for j, item2 in enumerate(item["content"]):
                if item2.get("type") == "image_url":
                    messages[i]["content"][j]["image_url"] = {
                        "url": f"data:image/jpeg;base64,{self.encode_image(item2['image_url']['url'])}"}
        return messages


    def image2text(self, instruction, num_retry=5):
        messages = copy.deepcopy(instruction['messages'])
        messages = self.update_message(messages)
        req_body['multimodal_messages'] = messages
        req_body["chain_name"] = "agent_marking_multimodal@v1.0.4" if self.model == 'aime-multimodal-ucwlai' else "agent_marking_multimodal@v1.0.3"
        start_time = time.time()
        response = request_chain(req_body, timeout=120)
        end_time = time.time()
        print(f"Request time: {end_time - start_time} seconds")
        if response.status_code != 200:
            if num_retry > 0:
                return self.image2text(instruction, num_retry - 1)
            else:
                raise Exception(f"Request failed after retries: {response.status_code}, {response.text}")
        stream = response.text.split('\n\n')
        reasoning_content = ''
        content = ''
        for chunk in stream:
            if chunk.startswith('data:'):
                chunk_data = json.loads(chunk[len('data:'):])
                if chunk_data['type'] == 'reasoning_content':
                    reasoning_content += chunk_data['data']
                elif chunk_data['type'] == 'plain':
                    content += chunk_data['data']
        if reasoning_content:
            result = '<think>' + reasoning_content + '</think>' + content
        else:
            result = content
        print(result)
        return result
     

